package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Ave; public class Pinguim extends Ave implements Nado, Predacao { public Pinguim(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " emite um grasnado curto."); } public void comer() { System.out.println(getNome() + " está comendo peixes pequenos."); } public void nadar() { System.out.println(getNome() + " está nadando com agilidade na água gelada."); } public void cacar() { System.out.println(getNome() + " está caçando krill no gelo."); } }
